"use client";

import { forwardRef } from "react";
import { useCalendar } from "./hooks/use-calendar-context";
import { Calendar01Root } from "./parts/calendar-root";
import { CalendarToolbar } from "./parts/calendar-toolbar";
import { CalendarMiniNav } from "./parts/calendar-mini-nav";
import { CalendarMonthView } from "./parts/calendar-month-view";
import { CalendarWeekView } from "./parts/calendar-week-view";
import { CalendarDayView } from "./parts/calendar-day-view";
import { CalendarAgendaView } from "./parts/calendar-agenda-view";
import type { CalendarHandle, CalendarProps } from "./types";

/** Renders the active view (must live inside the Root to read context). */
function ActiveView() {
  const { view, availableViews } = useCalendar();
  const v = availableViews.includes(view) ? view : availableViews[0];
  switch (v) {
    case "week":
      return <CalendarWeekView />;
    case "day":
      return <CalendarDayView />;
    case "agenda":
      return <CalendarAgendaView />;
    case "month":
    default:
      return <CalendarMonthView />;
  }
}

/**
 * Calendar 01 — batteries-included assembly (Tier A). Root + toolbar + optional
 * mini-nav + the active view, gated by `show*` toggles. Contains no logic the
 * parts lack; hand-assemble `Calendar01Root` + the parts you want for a lighter
 * build.
 */
export const Calendar01 = forwardRef<CalendarHandle, CalendarProps>(
  function Calendar01(props, ref) {
    const {
      showToolbar = true,
      showMiniNav = false,
      className,
      ...rootProps
    } = props;

    return (
      <Calendar01Root ref={ref} className={className} {...rootProps}>
        {showToolbar ? <CalendarToolbar /> : null}
        <div className="flex min-h-0 flex-1">
          {showMiniNav ? (
            <CalendarMiniNav className="hidden border-r border-border p-2 sm:block" />
          ) : null}
          <div className="min-w-0 flex-1 overflow-hidden">
            <ActiveView />
          </div>
        </div>
      </Calendar01Root>
    );
  },
);

// Assembly (Tier A)
export { Calendar01 } from "./calendar-01";

// Headless provider + context parts (Tier B) — flat exports, never a namespace
export { Calendar01Root } from "./parts/calendar-root";
export { CalendarToolbar } from "./parts/calendar-toolbar";
export { CalendarMonthView } from "./parts/calendar-month-view";
export { CalendarWeekView } from "./parts/calendar-week-view";
export { CalendarDayView } from "./parts/calendar-day-view";
export { CalendarAgendaView } from "./parts/calendar-agenda-view";
export { CalendarMiniNav } from "./parts/calendar-mini-nav";

// Standalone primitives (Tier C)
export {
  CalendarEventChip,
  CalendarEventBar,
  CalendarTimeBlock,
  NowIndicator,
  EventTooltip,
} from "./parts/calendar-event";
export { MonthDayCell } from "./parts/calendar-month-view";
export { TimeGrid, TimeGutter } from "./parts/calendar-time-grid";
export { AgendaRow } from "./parts/calendar-agenda-view";
export { CalendarSkeleton } from "./parts/calendar-skeleton";
export { CalendarFullCardTooltip } from "./parts/event-tooltip-full";

// Hook
export { useCalendar } from "./hooks/use-calendar-context";

// Public types (+ the consumed todo-rich-card data language, re-exported)
export type {
  CalendarProps,
  CalendarRootProps,
  CalendarHandle,
  CalendarView,
  WeekStart,
  EventKind,
  CalendarOccurrence,
  CalendarEventColor,
  CalendarStatusTone,
  CalendarTooltipRenderer,
  TodoItem,
  TodoPerson,
  TodoStatusOption,
  TodoPriorityOption,
  TodoLabelOption,
  TodoColorRamp,
  TodoPermissions,
  TodoPermissionRule,
  TodoPermissionReason,
  TodoItemAddedEvent,
  TodoItemRemovedEvent,
  TodoItemMovedEvent,
  TodoFieldEditedEvent,
  TodoStatusChangedEvent,
} from "./types";

import type { ReactNode } from "react";

/*
 * calendar-01 — the date-grid sibling of gantt-timeline-01.
 *
 * It consumes the SAME canonical TodoItem[] as the rest of the task family
 * (todo-rich-card / todo-tree / kanban-board-01 / gantt-timeline-01) and lays
 * the items onto a calendar grid (month / week / day / agenda) instead of a
 * continuous time axis. v1 is read-only; the editing surface is declared below
 * the `Editing (v0.2.0)` fence but inert in v1 (so v2 is purely additive).
 *
 * Cross-procomp reuse (mirrors gantt): the data + permission + event language
 * is IMPORTED from todo-rich-card via the same-category relative barrel and
 * RE-EXPORTED here, so a consumer importing the calendar gets the whole
 * vocabulary from one module. Rewriter-safe (same-category relative import).
 */
import type {
  TodoItem,
  TodoPerson,
  TodoStatusOption,
  TodoPriorityOption,
  TodoLabelOption,
  TodoColorRamp,
  TodoPermissions,
  TodoPermissionRule,
  TodoPermissionReason,
  TodoItemAddedEvent,
  TodoItemRemovedEvent,
  TodoItemMovedEvent,
  TodoFieldEditedEvent,
  TodoStatusChangedEvent,
} from "../todo-rich-card";

// Re-export the consumed data + editing language so a consumer importing the
// calendar gets item, option, permission, and event types without a second
// import (same-category barrel import; rewriter-safe).
export type {
  TodoItem,
  TodoPerson,
  TodoStatusOption,
  TodoPriorityOption,
  TodoLabelOption,
  TodoColorRamp,
  TodoPermissions,
  TodoPermissionRule,
  TodoPermissionReason,
  TodoItemAddedEvent,
  TodoItemRemovedEvent,
  TodoItemMovedEvent,
  TodoFieldEditedEvent,
  TodoStatusChangedEvent,
};

/* ───────── calendar enums + occurrence ───────── */

export type CalendarView = "month" | "week" | "day" | "agenda";

/** 0 = Sunday … 6 = Saturday (matches date-fns `weekStartsOn`). */
export type WeekStart = 0 | 1 | 2 | 3 | 4 | 5 | 6;

/** Semantic tone, mirrored from TodoStatusOption.tone. */
export type CalendarStatusTone = "active" | "done" | "blocked";

/** How an event is laid out. Derived (never stored on TodoItem) — see lib/classify.ts. */
export type EventKind = "all-day" | "timed" | "milestone";

export type CalendarEventColor = {
  fill: string;
  foreground: string;
  border?: string;
};

/**
 * Normalized, render-ready event — the output of lib/occurrences.ts. Exported
 * for advanced Tier-C use (like gantt's GanttRow / GanttBarGeometry).
 */
export type CalendarOccurrence = {
  /** The source item (the calendar never mutates it). */
  item: TodoItem;
  /** = item.id */
  id: string;
  kind: EventKind;
  /** Effective start, epoch ms (floating-local for date-only all-day). */
  startMs: number;
  /** Effective end, epoch ms (= startMs for a milestone). */
  endMs: number;
  /** kind !== "timed". */
  allDay: boolean;
  tone: CalendarStatusTone;
  color: CalendarEventColor;
  /** endMs < now && tone !== "done". */
  overdue: boolean;
  /** item.active === false. */
  inactive: boolean;
  /** Unparseable date → finite-guard; rendered label-only, no geometry. */
  invalid?: boolean;
};

export type CalendarTooltipRenderer = (
  item: TodoItem,
  occ: CalendarOccurrence,
) => ReactNode;

/* ───────── public component props ───────── */

export type CalendarProps = {
  // ── Data (identical surface to gantt / card / tree) ──
  data: TodoItem[];
  statusOptions?: TodoStatusOption[];
  priorityOptions?: TodoPriorityOption[];
  labelOptions?: TodoLabelOption[];
  /** Urgency ramp; RAMPS imported from todo-rich-card. */
  colorRamp?: TodoColorRamp;

  // ── Cursor: view + focus date (each controlled OR uncontrolled) ──
  defaultView?: CalendarView; // default "month"
  view?: CalendarView; // controlled
  onViewChange?: (view: CalendarView) => void;
  defaultDate?: Date; // default = now
  date?: Date; // controlled focus date
  onDateChange?: (date: Date) => void;
  /** Fires on every cursor move with the newly-visible window (lazy data fetch). */
  onRangeChange?: (range: {
    view: CalendarView;
    start: Date;
    end: Date;
  }) => void;

  // ── Calendar config ──
  weekStartsOn?: WeekStart; // default 1 (Mon)
  now?: Date | string; // SSR-stable now; client interval refreshes
  colorRefreshIntervalMs?: number; // urgency tick; default 60_000
  agendaRangeDays?: number; // default 30
  maxEventsPerCell?: number; // month overflow cap; default = height-responsive
  scrollToHour?: number; // time-grid initial scroll; default 8
  /** Classification escape hatch (layer 1 of the 3-layer rule). */
  classifyEvent?: (item: TodoItem) => EventKind | undefined;

  // ── Assembly toggles + layout ──
  showToolbar?: boolean; // default true (assembly only)
  showMiniNav?: boolean; // default false (assembly only)
  /** Trim the toolbar view switch + assembly's mountable views. Default all four. */
  views?: CalendarView[];
  className?: string;
  "aria-label"?: string;

  // ── Read-only interactions ──
  selectedId?: string | null;
  onSelect?: (itemId: string | null) => void;
  onTaskClick?: (item: TodoItem) => void;
  onDateClick?: (date: Date) => void;
  onShowMore?: (date: Date, items: TodoItem[]) => void;
  /** Override the hover tooltip; default = lightweight summary. */
  renderTooltip?: CalendarTooltipRenderer;

  // ══ Editing (v0.2.0) — ALL opt-in; default surface is the v1 read-only calendar ══
  /** Master switch. Default false → byte-identical v1 read-only behavior. */
  editable?: boolean;
  /** Full mutated forest after ANY edit; controlled consumer echoes into `data`. */
  onChange?: (data: TodoItem[]) => void;
  /** Reschedule sugar — fires alongside onChange/onFieldEdited (kept from gantt). */
  onTaskReschedule?: (next: {
    itemId: string;
    startAt: string;
    expireAt?: string;
  }) => void;
  // CRUD + field events (shapes reused verbatim from todo-rich-card)
  onItemAdded?: (event: TodoItemAddedEvent) => void;
  onItemRemoved?: (event: TodoItemRemovedEvent) => void;
  onItemMoved?: (event: TodoItemMovedEvent) => void;
  onFieldEdited?: (event: TodoFieldEditedEvent) => void;
  onStatusChanged?: (event: TodoStatusChangedEvent) => void;
  // Permissions (reused from todo-rich-card; mirrors gantt + tree)
  permissions?: TodoPermissions;
  canMoveItem?: (id: string) => boolean;
  canResizeItem?: (id: string) => boolean;
  canDeleteItem?: (id: string) => boolean;
  canCreateChild?: (id: string) => boolean;
  canEditItem?: (id: string) => boolean;
  onPermissionDenied?: (
    action: keyof TodoPermissionRule,
    itemId: string,
    reason: TodoPermissionReason,
  ) => void;
};

/** Headless provider props = assembly props minus the assembly-only toggles. */
export type CalendarRootProps = Omit<
  CalendarProps,
  "showToolbar" | "showMiniNav"
> & {
  children: ReactNode;
};

/* ───────── imperative handle ───────── */

export type CalendarHandle = {
  goToDate(date: Date): void;
  goToToday(): void;
  setView(view: CalendarView): void;
  next(): void;
  prev(): void;
  getVisibleRange(): { start: Date; end: Date };
  // Editing (v0.2.0) — no-ops when `editable` is false / permission denied.
  addTask(date: Date, item?: Partial<TodoItem>): void;
  deleteTask(itemId: string): void;
  editTask(itemId: string): void;
};

/* ───────── context (internal; constructed in the Root) ───────── */

export type CalendarContextValue = {
  // cursor
  view: CalendarView;
  focusDate: Date;
  visibleRange: { start: Date; end: Date };
  weekStartsOn: WeekStart;
  availableViews: CalendarView[];

  // data
  occurrences: CalendarOccurrence[];
  nowMs: number;

  // config
  agendaRangeDays: number;
  maxEventsPerCell?: number;
  scrollToHour: number;
  statusOptions?: TodoStatusOption[];
  priorityOptions?: TodoPriorityOption[];
  labelOptions?: TodoLabelOption[];

  // selection
  selectedId: string | null;

  // cursor actions
  setView(view: CalendarView): void;
  goToDate(date: Date): void;
  goToToday(): void;
  next(): void;
  prev(): void;
  select(id: string | null): void;

  // read-only interaction callbacks
  onTaskClick?: (item: TodoItem) => void;
  onDateClick?: (date: Date) => void;
  onShowMore?: (date: Date, items: TodoItem[]) => void;
  renderTooltip?: CalendarTooltipRenderer;
};

/**
 * Date parsing + the §7-D5 three-layer all-day/timed/milestone classification.
 * Pure; framework-free.
 */
import type { EventKind, TodoItem } from "../types";

const DATE_ONLY_RE = /^\d{4}-\d{2}-\d{2}$/;
const MS_PER_DAY = 86_400_000;

export type ParsedDate = {
  /** Epoch ms, or NaN if unparseable. */
  ms: number;
  /** True when the source was a bare YYYY-MM-DD (no time component). */
  dateOnly: boolean;
};

/**
 * Parse a TodoItem ISO date value. A bare calendar date (YYYY-MM-DD, no `T`)
 * is treated as an ALL-DAY, timezone-independent date and parsed as a FLOATING
 * LOCAL date — NOT via `Date.parse`, which per spec reads "2026-06-22" as UTC
 * midnight and renders a day early in negative-UTC offsets. Full timestamps go
 * through `Date.parse` unchanged (matching the rest of the family).
 */
export function parseDateValue(value: string | undefined): ParsedDate {
  if (!value) return { ms: NaN, dateOnly: false };
  if (DATE_ONLY_RE.test(value)) {
    const [y, m, d] = value.split("-").map(Number);
    return { ms: new Date(y, m - 1, d).getTime(), dateOnly: true };
  }
  return { ms: Date.parse(value), dateOnly: false };
}

/** Effective start (floating-local for date-only). */
export function effectiveStart(item: TodoItem): ParsedDate {
  return parseDateValue(item.startAt ?? item.setAt);
}

/**
 * Effective end. `expireAt` wins; else `start + duration`; else null (no end).
 * `ms: NaN` signals an unparseable `expireAt`.
 */
export function effectiveEnd(
  item: TodoItem,
  startMs: number,
): { ms: number | null; dateOnly: boolean } {
  if (item.expireAt) {
    const p = parseDateValue(item.expireAt);
    return { ms: p.ms, dateOnly: p.dateOnly };
  }
  if (item.duration != null) {
    return { ms: startMs + item.duration, dateOnly: false };
  }
  return { ms: null, dateOnly: false };
}

/**
 * Three-layer rule, first match wins (§7-D5):
 *   1. consumer `classifyEvent` predicate (if it returns a kind)
 *   2. no end:  date-only start ⇒ all-day (a bare date = an all-day event);
 *               otherwise ⇒ milestone (a precise instant / deadline)
 *   3. date-only start or end ⇒ all-day (Google's mechanism)
 *   4. span ≥ 1 full day ⇒ all-day
 *   5. otherwise ⇒ timed
 */
export function classify(
  item: TodoItem,
  classifyEvent?: (item: TodoItem) => EventKind | undefined,
): EventKind {
  const override = classifyEvent?.(item);
  if (override) return override;

  const start = effectiveStart(item);
  const end = effectiveEnd(item, start.ms);

  if (end.ms == null) return start.dateOnly ? "all-day" : "milestone";
  if (start.dateOnly || end.dateOnly) return "all-day";

  const span = end.ms - start.ms;
  if (Number.isFinite(span) && span >= MS_PER_DAY) return "all-day";
  return "timed";
}

/**
 * Event color resolution. The OKLCH urgency ramp is IMPORTED from todo-rich-card
 * (`RAMPS`) — not re-derived — so the calendar matches the card + gantt exactly.
 * Only the done/blocked tones are adapted (muted / destructive).
 *
 * `RAMPS` must be the FIRST `from`-import so the meta-deps audit registers the
 * todo-rich-card dependency (blackboard-01 / content-composer-01 lesson).
 */
import { RAMPS } from "../../todo-rich-card";
import type {
  CalendarEventColor,
  CalendarStatusTone,
  TodoColorRamp,
  TodoItem,
  TodoStatusOption,
} from "../types";

export function toneFor(
  item: TodoItem,
  statusOptions?: TodoStatusOption[],
): CalendarStatusTone {
  const opt = statusOptions?.find((o) => o.value === item.status);
  return opt?.tone ?? "active";
}

/** Resolve a `TodoColorRamp` (preset name | custom fn) into a callable. */
export function resolveRamp(
  ramp: TodoColorRamp | undefined,
): (t: number) => string {
  if (ramp == null) return RAMPS.default;
  if (typeof ramp === "function") return ramp;
  return RAMPS[ramp] ?? RAMPS.default;
}

/** Fraction 0..1 of the window elapsed at `nowMs`. */
export function elapsedFraction(
  startMs: number,
  endMs: number,
  nowMs: number,
): number {
  if (!Number.isFinite(startMs) || !Number.isFinite(endMs) || endMs <= startMs) {
    return 0;
  }
  const f = (nowMs - startMs) / (endMs - startMs);
  return f < 0 ? 0 : f > 1 ? 1 : f;
}

/**
 * Resolve the accent color for an event:
 *   borderColor override → that color (skips the engine)
 *   tone "done"          → muted-foreground
 *   tone "blocked"       → destructive
 *   tone "active"        → time-urgency ramp (fresh → red)
 *
 * The accent is used as the chip/block border + text; the surface tints it
 * (color-mix) for the background — same accent, light fill.
 */
export function eventColor(
  item: TodoItem,
  tone: CalendarStatusTone,
  startMs: number,
  endMs: number,
  nowMs: number,
  ramp: (t: number) => string,
): CalendarEventColor {
  let accent: string;
  if (item.borderColor) accent = item.borderColor;
  else if (tone === "done") accent = "var(--muted-foreground)";
  else if (tone === "blocked") accent = "var(--destructive)";
  else accent = ramp(elapsedFraction(startMs, endMs, nowMs));
  return { fill: accent, foreground: accent, border: accent };
}

/**
 * Calendar date math — pure, framework-free, all via date-fns (DST-correct by
 * construction). Maps the cursor (view + focus date) to the visible range and
 * the per-view day grids.
 */
import {
  addDays,
  addMonths,
  addWeeks,
  eachDayOfInterval,
  endOfMonth,
  endOfWeek,
  startOfDay,
  startOfMonth,
  startOfWeek,
} from "date-fns";
import type { CalendarView, WeekStart } from "../types";

/** The inclusive-start / exclusive-ish-end window the active view covers. */
export function visibleRange(
  view: CalendarView,
  focusDate: Date,
  weekStartsOn: WeekStart,
  agendaRangeDays: number,
): { start: Date; end: Date } {
  switch (view) {
    case "month": {
      return {
        start: startOfWeek(startOfMonth(focusDate), { weekStartsOn }),
        end: endOfWeek(endOfMonth(focusDate), { weekStartsOn }),
      };
    }
    case "week": {
      return {
        start: startOfWeek(focusDate, { weekStartsOn }),
        end: endOfWeek(focusDate, { weekStartsOn }),
      };
    }
    case "day": {
      const s = startOfDay(focusDate);
      return { start: s, end: addDays(s, 1) };
    }
    case "agenda": {
      const s = startOfDay(focusDate);
      return { start: s, end: addDays(s, Math.max(1, agendaRangeDays)) };
    }
  }
}

/** Full weeks (5–6 rows × 7 days) covering the focus month. */
export function monthGrid(focusDate: Date, weekStartsOn: WeekStart): Date[][] {
  const { start, end } = visibleRange("month", focusDate, weekStartsOn, 0);
  const days = eachDayOfInterval({ start, end });
  const weeks: Date[][] = [];
  for (let i = 0; i < days.length; i += 7) weeks.push(days.slice(i, i + 7));
  return weeks;
}

/** The 7 day columns of the focus week. */
export function weekColumns(focusDate: Date, weekStartsOn: WeekStart): Date[] {
  const s = startOfWeek(focusDate, { weekStartsOn });
  return Array.from({ length: 7 }, (_, i) => addDays(s, i));
}

/** The consecutive days an agenda window spans (for day grouping). */
export function agendaDays(focusDate: Date, agendaRangeDays: number): Date[] {
  const s = startOfDay(focusDate);
  return Array.from({ length: Math.max(1, agendaRangeDays) }, (_, i) =>
    addDays(s, i),
  );
}

/** Step the focus date by one view-relative period. `dir` = +1 / −1. */
export function stepDate(
  view: CalendarView,
  focusDate: Date,
  dir: number,
  agendaRangeDays: number,
): Date {
  switch (view) {
    case "month":
      return addMonths(focusDate, dir);
    case "week":
      return addWeeks(focusDate, dir);
    case "day":
      return addDays(focusDate, dir);
    case "agenda":
      return addDays(focusDate, dir * Math.max(1, agendaRangeDays));
  }
}

/** 0..23 — the hour rows of a time-grid. */
export const HOURS: number[] = Array.from({ length: 24 }, (_, h) => h);

/**
 * TodoItem[] → CalendarOccurrence[] — the single normalization pass.
 * Pure; framework-free. Flattens `children` (every dated item renders; no WBS
 * rollup — D10), computes the effective window with finite guards (never a NaN
 * geometry / `toISOString` throw — gantt v0.3.1 G2 lesson), classifies, and
 * resolves color via the shared engine.
 */
import { classify, effectiveEnd, effectiveStart } from "./classify";
import { eventColor, resolveRamp, toneFor } from "./color";
import type {
  CalendarOccurrence,
  EventKind,
  TodoColorRamp,
  TodoItem,
  TodoStatusOption,
} from "../types";

export type OccurrenceContext = {
  nowMs: number;
  classifyEvent?: (item: TodoItem) => EventKind | undefined;
  statusOptions?: TodoStatusOption[];
  colorRamp?: TodoColorRamp;
};

export function toOccurrences(
  data: TodoItem[],
  ctx: OccurrenceContext,
): CalendarOccurrence[] {
  const ramp = resolveRamp(ctx.colorRamp);
  const out: CalendarOccurrence[] = [];

  const walk = (item: TodoItem) => {
    const kind = classify(item, ctx.classifyEvent);
    const start = effectiveStart(item);
    const end = effectiveEnd(item, start.ms);

    const startMs = start.ms;
    const rawEnd = end.ms == null ? startMs : end.ms; // no end ⇒ point
    const invalid =
      !Number.isFinite(startMs) || (end.ms != null && !Number.isFinite(end.ms));

    // Finite guard: never emit a NaN geometry.
    let endMs = Number.isFinite(rawEnd) ? rawEnd : startMs;
    if (Number.isFinite(startMs) && Number.isFinite(endMs) && endMs < startMs) {
      endMs = startMs;
    }

    const tone = toneFor(item, ctx.statusOptions);
    const overdue =
      Number.isFinite(endMs) && endMs < ctx.nowMs && tone !== "done";
    const color = eventColor(item, tone, startMs, endMs, ctx.nowMs, ramp);

    out.push({
      item,
      id: item.id,
      kind,
      startMs,
      endMs,
      allDay: kind !== "timed",
      tone,
      color,
      overdue,
      inactive: item.active === false,
      invalid: invalid || undefined,
    });

    item.children?.forEach(walk);
  };

  data.forEach(walk);
  return out;
}

/** Occurrences whose covered span intersects [startMs, endMs). */
export function occurrencesInRange(
  occ: CalendarOccurrence[],
  startMs: number,
  endMs: number,
): CalendarOccurrence[] {
  return occ.filter(
    (o) => !o.invalid && o.endMs >= startMs && o.startMs < endMs,
  );
}

/**
 * Month-grid layout — pure. Lays a week's occurrences into horizontal lanes:
 * multi-day events become spanning bar segments (clipped per week row, with
 * continuation flags), single-day events occupy one column. Overflow past the
 * lane cap becomes a per-day "+N more" count.
 */
import { addDays, differenceInCalendarDays, startOfDay } from "date-fns";
import type { CalendarOccurrence } from "../types";

/**
 * First/last covered calendar day (local). All-day end is EXCLUSIVE at local
 * midnight (iCal / Google semantics): an event 00:00 Mon → 00:00 Wed covers
 * Mon + Tue.
 */
export function coveredDays(occ: CalendarOccurrence): {
  firstMs: number;
  lastMs: number;
} {
  const first = startOfDay(occ.startMs).getTime();
  let lastDay = startOfDay(occ.endMs);
  if (occ.endMs === lastDay.getTime() && lastDay.getTime() > first) {
    lastDay = addDays(lastDay, -1); // exclusive midnight end
  }
  return { firstMs: first, lastMs: Math.max(first, lastDay.getTime()) };
}

export type MonthSegment = {
  occ: CalendarOccurrence;
  lane: number;
  startCol: number; // 0..6 within the week
  endCol: number; // 0..6
  continuesLeft: boolean; // clipped at the week's left edge
  continuesRight: boolean; // clipped at the week's right edge
  spanning: boolean; // endCol > startCol → bar, else chip
};

export type MonthWeekLayout = {
  segments: MonthSegment[]; // lane < cap
  overflow: number[]; // hidden-count per day-column (length 7)
  laneCount: number; // lanes actually rendered (≤ cap)
};

/** Lay one week (7 startOfDay dates) into ≤ `cap` lanes. */
export function layoutMonthWeek(
  weekDays: Date[],
  occurrences: CalendarOccurrence[],
  cap: number,
): MonthWeekLayout {
  const weekStart = startOfDay(weekDays[0]).getTime();
  const weekEnd = startOfDay(weekDays[6]).getTime();

  type Placed = { occ: CalendarOccurrence; startCol: number; endCol: number };
  const placed: Placed[] = [];
  for (const occ of occurrences) {
    if (occ.invalid) continue;
    const { firstMs, lastMs } = coveredDays(occ);
    if (lastMs < weekStart || firstMs > weekEnd) continue;
    const startCol = Math.max(
      0,
      differenceInCalendarDays(new Date(Math.max(firstMs, weekStart)), weekDays[0]),
    );
    const endCol = Math.min(
      6,
      differenceInCalendarDays(new Date(Math.min(lastMs, weekEnd)), weekDays[0]),
    );
    placed.push({ occ, startCol, endCol });
  }

  // All-day / multi-day first (earlier start, then longer span), timed after.
  placed.sort((a, b) => {
    const am = a.occ.allDay ? 0 : 1;
    const bm = b.occ.allDay ? 0 : 1;
    if (am !== bm) return am - bm;
    if (a.startCol !== b.startCol) return a.startCol - b.startCol;
    return b.endCol - b.startCol - (a.endCol - a.startCol);
  });

  const laneOccupancy: boolean[][] = []; // [lane][col]
  const overflow = new Array(7).fill(0);
  const segments: MonthSegment[] = [];
  let laneCount = 0;

  for (const p of placed) {
    let lane = 0;
    for (;;) {
      if (!laneOccupancy[lane]) laneOccupancy[lane] = new Array(7).fill(false);
      let free = true;
      for (let c = p.startCol; c <= p.endCol; c++) {
        if (laneOccupancy[lane][c]) {
          free = false;
          break;
        }
      }
      if (free) break;
      lane++;
    }
    for (let c = p.startCol; c <= p.endCol; c++) laneOccupancy[lane][c] = true;

    if (lane >= cap) {
      for (let c = p.startCol; c <= p.endCol; c++) overflow[c]++;
      continue;
    }
    laneCount = Math.max(laneCount, lane + 1);
    const { firstMs, lastMs } = coveredDays(p.occ);
    segments.push({
      occ: p.occ,
      lane,
      startCol: p.startCol,
      endCol: p.endCol,
      continuesLeft: firstMs < weekStart,
      continuesRight: lastMs > weekEnd,
      spanning: p.endCol > p.startCol,
    });
  }

  return { segments, overflow, laneCount };
}

/** Every occurrence covering a given day (for the "+N more" popover list). */
export function occurrencesOnDay(
  occ: CalendarOccurrence[],
  day: Date,
): CalendarOccurrence[] {
  const dayStart = startOfDay(day).getTime();
  return occ.filter((o) => {
    if (o.invalid) return false;
    const { firstMs, lastMs } = coveredDays(o);
    return dayStart >= firstMs && dayStart <= lastMs;
  });
}

/**
 * Week/Day time-grid overlap packing — pure. Classic greedy interval-graph
 * column assignment: overlapping timed events split into side-by-side lanes;
 * each cluster reports its lane count so blocks can size to `1 / laneCount`.
 */
import type { CalendarOccurrence } from "../types";

export type PackedBlock = {
  occ: CalendarOccurrence;
  lane: number; // 0-based column within its cluster
  laneCount: number; // columns in the cluster (block width = 1 / laneCount)
};

export function packLanes(timed: CalendarOccurrence[]): PackedBlock[] {
  const sorted = [...timed].sort(
    (a, b) => a.startMs - b.startMs || a.endMs - b.endMs,
  );

  const out: PackedBlock[] = [];
  let cluster: { occ: CalendarOccurrence; lane: number }[] = [];
  let clusterEnd = -Infinity;
  const laneEnds: number[] = []; // end ms per active lane

  const flush = () => {
    if (!cluster.length) return;
    const laneCount = Math.max(1, ...cluster.map((c) => c.lane + 1));
    for (const c of cluster) out.push({ occ: c.occ, lane: c.lane, laneCount });
    cluster = [];
    laneEnds.length = 0;
  };

  for (const occ of sorted) {
    // A gap with no overlap closes the current cluster.
    if (cluster.length && occ.startMs >= clusterEnd) flush();

    let lane = laneEnds.findIndex((end) => end <= occ.startMs);
    if (lane === -1) {
      lane = laneEnds.length;
      laneEnds.push(occ.endMs);
    } else {
      laneEnds[lane] = occ.endMs;
    }
    cluster.push({ occ, lane });
    clusterEnd = Math.max(clusterEnd, occ.endMs);
  }
  flush();
  return out;
}

/** Vertical placement of a timed block within a day column, as 0..1 fractions. */
export function blockOffsets(
  occ: CalendarOccurrence,
  dayStartMs: number,
): { top: number; height: number } {
  const dayMs = 86_400_000;
  const top = Math.max(0, (occ.startMs - dayStartMs) / dayMs);
  const rawH = (occ.endMs - occ.startMs) / dayMs;
  // Minimum height so a very short event is still tappable.
  const height = Math.min(1 - top, Math.max(rawH, 0.02));
  return { top, height };
}

